class Solution {

    private double radius;
    private double x_center;
    private double y_center;
    private double angle;
    private double radius_squared;

    public Solution(double radius, double x_center, double y_center) {
        this.radius = radius;
        this.x_center = x_center;
        this.y_center = y_center;
        this.angle = Math.random() * 2 * Math.PI;
        this.radius_squared = radius * radius;
    }

    public double[] randPoint() {
        double distance_squared = Math.random() * radius_squared;
        double r = Math.sqrt(distance_squared);
        double x = x_center + r * Math.cos(angle);
        double y = y_center + r * Math.sin(angle);
        return new double[] {x, y};
    }
}
